package com.trademaster.ims.mobile.fulfillment.model;
import jakarta.persistence.*;import java.math.BigDecimal;import java.time.Instant;
@Entity @Table(name="cod_collections",uniqueConstraints={@UniqueConstraint(name="uk_cod_collection_order",columnNames="order_id"),@UniqueConstraint(name="uk_cod_collection_payment",columnNames="payment_id")},indexes=@Index(name="idx_cod_collection_status",columnList="status"))public class CODCollection{public enum Status{COD_PENDING,CASH_COLLECTED,COLLECTION_MISMATCH,RECONCILED,FAILED_COLLECTION,WAIVED,CANCELLED} @Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="order_id",nullable=false)private Long orderId;@Column(name="payment_id",nullable=false)private Long paymentId;@Column(name="fulfillment_id",nullable=false)private Long fulfillmentId;@Column(name="expected_amount",nullable=false,precision=15,scale=2)private BigDecimal expectedAmount;@Column(name="collected_amount",precision=15,scale=2)private BigDecimal collectedAmount;@Enumerated(EnumType.STRING)@Column(nullable=false,length=32)private Status status=Status.COD_PENDING;@Column(name="collected_at")private Instant collectedAt;@Column(name="collected_by",length=120)private String collectedBy;@Column(name="reconciliation_reference",length=120)private String reconciliationReference;@Column(length=700)private String note;@Column(name="created_at",nullable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;@Version private Long version;@PrePersist void p(){Instant n=Instant.now();createdAt=n;updatedAt=n;}@PreUpdate void u(){updatedAt=Instant.now();}public Long getId(){return id;}public Long getOrderId(){return orderId;}public void setOrderId(Long v){orderId=v;}public Long getPaymentId(){return paymentId;}public void setPaymentId(Long v){paymentId=v;}public Long getFulfillmentId(){return fulfillmentId;}public void setFulfillmentId(Long v){fulfillmentId=v;}public BigDecimal getExpectedAmount(){return expectedAmount;}public void setExpectedAmount(BigDecimal v){expectedAmount=v;}public BigDecimal getCollectedAmount(){return collectedAmount;}public void setCollectedAmount(BigDecimal v){collectedAmount=v;}public Status getStatus(){return status;}public void setStatus(Status v){status=v;}public Instant getCollectedAt(){return collectedAt;}public void setCollectedAt(Instant v){collectedAt=v;}public String getCollectedBy(){return collectedBy;}public void setCollectedBy(String v){collectedBy=v;}public String getReconciliationReference(){return reconciliationReference;}public void setReconciliationReference(String v){reconciliationReference=v;}public String getNote(){return note;}public void setNote(String v){note=v;}public Instant getCreatedAt(){return createdAt;}public Instant getUpdatedAt(){return updatedAt;}public Long getVersion(){return version;}}